var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"카페에 통로를 숨겨뒀다고?","JPN":"カフェに通路を隠してたの？","ENG":"So there's a portal hidden in the cafe?","TWN":"居然在咖啡店裡隱藏了通道？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그 마녀들이 아주 재미있는 소꿉장난을 하고 있었네.","JPN":"あの魔女たち、とても面白いままごとをしていたわね。","ENG":"Those witches have been playing a cute little game, haven't they?","TWN":"這些魔女們是在玩扮家家酒嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"좋아. 나의 사랑스런 꼭두각시들아.","JPN":"さあ。私の可愛い操り人形たち。","ENG":"Very well, my beloved puppets.","TWN":"好了，我親愛的傀儡們。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"내 최고의 인형이 숨겨져 있는 곳으로 길을 안내해 주렴.","JPN":"私の最高の人形が隠されている場所に案内して。","ENG":"Lead me to where my greatest puppet is hidden.","TWN":"帶我去找我最棒的木偶吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"알겠...... 습니다. 주인님.","JPN":"わかり……ました。マスター。","ENG":"Yes... Master.","TWN":"好……的，主人。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이게 다 무슨 일이죠?","JPN":"いったいどういうことですか？","ENG":"What’s going on?","TWN":"怎麼回事啊？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"왜 인형들이 사람을 습격하고 잉그리드는 저 사람을 순순히 따라가는 거죠?","JPN":"どうして人形たちが人を襲って、イングリッドはおとなしくあの人について行ったんですか……？","ENG":"Why are the puppets attacking people? And why's Ingrid following that woman willingly?","TWN":"為什麼木偶會襲擊人，而且英格麗還乖乖地跟著他走？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"무슨 인형이라도 되어버린 것처럼......!","JPN":"まるで人形にでもなってしまったみたいに……！","ENG":"It's as if she's become a puppet herself!","TWN":"就好像變成了木偶一樣……！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......내 실수야.","JPN":"……妾の失態だ｡","ENG":"It's my bad.","TWN":"…………是我的錯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 실수라뇨?","JPN":"え？　失態？","ENG":"Huh? What do you mean?","TWN":"什麼？妳的錯？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"저번에 갔던 발푸르기스 성 기억하지?","JPN":"先日行ったヴァルプルギス城を覚えてるわね?","ENG":"Remember that Walpurgis Castle you saw last time?","TWN":"妳還記得上次去的魔女之夜城吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그 성의 가장 깊은 곳에는 아주 오래되고 강력한 인형이 잠들어 있어.","JPN":"あの城の最奥には、とても古く強力な人形が眠ってるの｡","ENG":"In the deepest reaches of the castle sleeps an ancient, powerful puppet.","TWN":"在魔女之夜城的最深處，沉睡著歷史悠久且強大的木偶。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"인형이라면...... 그 3종 침식체들이요?","JPN":"人形って……あの第3種侵食体のことですか？","ENG":"Puppet? You mean like those Category 3 C.O.s?","TWN":"木偶……妳是說3類侵蝕體？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아니, 그건 그 인형이 만들어 낸 장난감들 중 하나에 불과해.","JPN":"いえ、あれはその人形が作り出したおもちゃの一つにすぎないわ。","ENG":"No. They are merely toys crafted by the puppet.","TWN":"不，那只是那些木偶做出的玩具之一。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"발푸르기스 성에 가둔 <color=#ffd34c>최초의 인형</color>은 그것과는 비교도 안 될 만큼 끔찍한 존재야.","JPN":"ヴァルプルギス城に閉じ込めた<color=#ffd34c>最初の人形</color>は、\\n侵食体とは比べものにならないほどおぞましい存在だわ。","ENG":"The <color=#ffd34c>Original Puppet</color> trapped in Walpurgis Castle is a terrifying being beyond comparison.","TWN":"關在魔女之夜城的<color=#ffd34c>最初的木偶</color>是比那個還要可怕的存在。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"메이 할머니는 주인이 그 인형을 되찾지 못하게 솔라 코덱스의 힘으로 발푸르기스 성과 주변의 이면세계 전체를 격리해서 봉인했어.","JPN":"メイ婆さんはマスターがその人形を取り戻せないように、\\nソーラーコーデックスの力でヴァルプルギス城と周辺の裏世界全体を隔離して封印した。","ENG":"Granny May used the Solar Codex to quarantine the entire area around the castle in the Counterside so the Puppet Master could not access the Original Puppet.","TWN":"梅伊奶奶為了不讓木偶的主人找到它，用太陽法典的力量隔離並封印了魔女之夜城和周圍的整個異界。"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"카페 지하실의 통로가 그 장소로 들어갈 수 있는 유일한 길이야.","JPN":"カフェの地下室の通路がその場所に入れる唯一のルートだ。","ENG":"The portal in the cafe's basement is the only way to get to it.","TWN":"咖啡店地下室的通道，是唯一可以進入那個地方的道路。"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우린 그동안 침입자가 들어오지 못하게 거길 지키고 있었고.","JPN":"今まで妾たちは侵入者が入らないように守っていたんだ。","ENG":"And we've been protecting it against any intruders.","TWN":"而我們一直守著那個通道，防止入侵者侵入。"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 잉그리드가 간 곳은......","JPN":"じゃあ、イングリッドが向かった場所って……","ENG":"You mean Ingrid is headed to...","TWN":"那英格麗去的地方是……"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아마 카페 지하실을 통해 발푸르기스의 성으로 갔을 거야.","JPN":"おそらく、カフェの地下室を経由してヴァルプルギス城に向かったはずだ。","ENG":"My guess is that she and the others went to Walpurgis Castle through the basement.","TWN":"應該是通過咖啡店地下室去了魔女之夜城。"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"인형의 주인이 자신의 인형을 찾으러 간 거지.","JPN":"人形の持ち主が自分の人形を取り戻しに行ったのさ。","ENG":"The Puppet Master probably wants to reclaim her puppet.","TWN":"木偶的主人要尋回自己的木偶了。"},"stage":{"bg":"SS_STREGA_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"주인이라면...... 그 단장님이요?","JPN":"マスターは……あの団長？","ENG":"The Puppet Master... You mean Harab?","TWN":"主人……妳是說那個團長嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래. 메이 할머니가 평생 동안 싸워 왔던 우리의 적이지.","JPN":"そうだ。メイ婆さんが生涯戦ってきた妾たちの敵だ。","ENG":"Yes. She is the enemy that Granny May confronted throughout her life.","TWN":"嗯，讓梅伊奶奶奮鬥一生的我們的敵人。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"할머니가......","JPN":"おばあちゃんが……","ENG":"Grandma did...","TWN":"奶奶她……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"마지막에 봤을 때랑 얼굴이 너무 달라서 녀석이라는 걸 눈치 못 챘어.","JPN":"最後に会った時と顔が全然違っていたから奴だと気づかなかった。","ENG":"I couldn't recognize her at first, because her face changed so much since we saw her last.","TWN":"他的臉和我最後一次見到的太不一樣了，所以我沒有認出來。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"근처에 와 있는지 알았으면 할로윈 코스튬 같은 건 만들지 않았을 텐데......","JPN":"近くに来ていることをわかっていたら、ハロウィン衣装なんか作らなかったのに……","ENG":"If we knew she was around, we would have never made those costumes...","TWN":"如果我知道他來到了這裡，我是不會做什麼萬聖節服裝的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 할로윈 코스튬이랑 지금 일어난 일이 무슨 상관인데요?","JPN":"ハロウィン衣装とこの出来事って関係があるんですか？","ENG":"Huh? What do Halloween costumes have to with what's happened?","TWN":"什麼？萬聖節服裝和這個有什麼關係嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우리가 만든 코스튬에 발푸르기스 성에서 쓰러뜨린 인형의 재료를 넣었잖아.","JPN":"妾たちが作った衣装はヴァルプルギス城で倒した人形の材料を使っている。","ENG":"We included parts from the Walpurgis puppets in the costumes, remember?","TWN":"我們不是把魔女之夜城的木偶當作材料製作服裝了嗎。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"인형의 주인은 자기 마력이 담긴 옷을 입은 사람을 꼭두각시로 만들 수 있어.","JPN":"人形の持ち主は、自分の魔力が込められた服を着た人を操り人形にできるんだ。","ENG":"The Puppet Master can turn anyone into a puppet if they're wearing clothes imbued with her magic.","TWN":"而木偶的主人可以把穿著蘊含自己魔力服裝的人變成傀儡。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그걸 알면서 코스튬을 만든 거예요? 너무 위험하잖아요!","JPN":"それを知ってたのに衣装を作ったんですか？　危険すぎます！","ENG":"You made those costumes in full knowledge of that? But it's too dangerous!","TWN":"妳既然知道，那為什麼還要做成服裝？這太危險了！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"결계가 정상이었을 때는 괜찮았어. 결계가 주인과의 연결을 끊어 줬으니까.","JPN":"結界が正常だった時は問題なかったわ。結界が持ち主との繋がりを切ってたんだから。","ENG":"It was fine when the barrier was working properly. It severed the puppets' connection to the Puppet Master.","TWN":"結界還正常的時候是沒關係的，因為結界阻斷了木偶和主人的聯繫。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"메이 할머니가 돌아가신 후에 결계가 약해진 건 알고 있었지만 그래도 인형의 마력은 거의 남아 있지 않았는데.","JPN":"メイお婆ちゃんが亡くなってから結界が弱くなってきたことはわかってたけど、\\n人形の魔力はもうほとんど残っていないはず。","ENG":"We did realize the barrier had grown weaker after Granny May's passing, but we thought it was okay because there was so little mana left in the puppets.","TWN":"梅伊奶奶去世之後，結界變弱了，但木偶的魔力基本上也沒剩多少了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"공교롭게도 인형의 주인이 이렇게 가까이 와 있어서 그 미량의 마력을 눈치챈 것 같아.","JPN":"でも、運が悪いことに人形の持ち主がこんなに近くにいて、\\nその微量な魔力に気づいたみたいだわ。","ENG":"But as it happened, the Puppet Master came here and noticed that tiny amount of residual mana.","TWN":"不巧的是，木偶的主人悄無聲息地來到了這裡，並且感覺到了那少量的魔力。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하필이면 일이 이렇게 겹치게 될 줄은......","JPN":"よりによってこんなタイミングに……","ENG":"We just had no idea it would all come together like this...","TWN":"我沒想到事情會變成這個樣子……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아니, 이건 변명의 여지가 없는 우리의 실수야.","JPN":"いや、これは弁解の余地もない妾たちの失態だ。","ENG":"No, this was clearly our mistake. There's no excuse.","TWN":"不，這就是我們的錯，百口莫辯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"적어도 결계를 보강할 때까지는 수집한 재료를 사용하지 말았어야 했어.","JPN":"せめて結界を補強するまでは集めた材料を使うべきじゃなかった。","ENG":"At the very least, we should have refrained from using those materials until we repaired the barrier.","TWN":"在加固結界之前，就不該用收集到的材料。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그러니까 책임을 져야겠지.","JPN":"だから、責任は取らないといけない。","ENG":"So we must take responsibility for this.","TWN":"所以我們要為此負責。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우린 세 사람을 구하러 발푸르기스 성으로 갈 거야.","JPN":"妾たちは3人を助けるためにヴァルプルギス城に行く。","ENG":"We'll head to Walpurgis Castle to save those three.","TWN":"我們要去魔女之夜城，救出那三個人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"넌 그 동안 안전한 곳에 피해 있어.","JPN":"その間、汝は安全な場所に隠れてろ。","ENG":"You stand by somewhere safe in the meantime.","TWN":"這段時間，妳先躲在安全的地方。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저도 같이 갈래요! 잉그리드는 제 친구라고요!","JPN":"私も一緒に行かせてください！　イングリッドは私の友達なんです！","ENG":"I'll go with you! Ingrid is my friend!","TWN":"我也要一起去！英格麗是我的朋友！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"바보 같은 소리 하지 마, 바보야.","JPN":"馬鹿なことを言うな。","ENG":"Don't be stupid.","TWN":"別說這種蠢話。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"지금부터의 싸움은 장난이 아니라고! 진짜 죽을 수도 있어!","JPN":"これからの戦いは遊びじゃない！　本当に死ぬかもしれないんだぞ！","ENG":"This is no joke! You could actually get killed!","TWN":"這不是在開玩笑！一不小心就會丟掉性命！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......미안하지만, 메이 할머니에게는 빚을 많이 졌어.","JPN":"……メイ婆さんにはずっとお世話になりっぱなしだった。","ENG":"Sorry, but we owe too much to Granny May.","TWN":"……我們欠梅伊奶奶太多太多了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"손녀인 널 위험한 곳으로 끌고 들어가고 싶진 않아.","JPN":"孫である汝を危険な場所に連れて行きたくないのだ。","ENG":"We don't want to put her granddaughter in harm's way.","TWN":"我不想連累她的孫女。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"플루토. 우리가 다녀올 때까지 저 바보를 지켜 줘.","JPN":"プルートー。妾たちが戻ってくるまであのアホを守ってほしい。","ENG":"Pluto. Keep this little fool safe until we return.","TWN":"布魯托，這期間就拜託你照顧她了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹~","JPN":"にゃあ～。","ENG":"Meow!","TWN":"喵喵~"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"가자, 에블린. 인형의 주인을 따라잡으려면 서둘러야 해.","JPN":"行こう、エヴリン。人形の持ち主に追いつくためにも急がないと。","ENG":"Let's go, Evelyn. We better hurry if we want to catch up with the Puppet Master.","TWN":"走吧，伊芙琳。我們要加快腳步追上木偶的主人了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이미 준비 끝났어. 오랜만에 전투용 비약들을 시험해 보겠는걸?","JPN":"準備はもうできてるわ。久々に戦闘用の秘薬を試すことができるのね。","ENG":"I'm ready to go. I guess I'll finally get to test out these new combat potions!","TWN":"我早就準備好了。好久沒試試戰鬥秘藥了！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};